mapper.select:
select * from ( select rownum rn, I.* from ( SELECT G.GHP_ID AS ghpId, G.GHP_NAME AS ghpName, G.GHP_CATEGORY AS ghpCategory, G.GHP_STANDARD AS ghpStandard, G.GHP_CHECK_METHOD AS ghpCheckMethod, G.GHP_CYCLE AS ghpCycle, NVL(G.GHP_WH_TYPE, 0) AS ghpWhType, NVL(G.GHP_WP_TYPE, 0) AS ghpWpType, WP.WP_TYPE_NAME AS wpTypeName, WH.WH_TYPE_NAME AS whTypeName, G.GHP_MIN_VALUE AS ghpMinValue, G.GHP_MAX_VALUE AS ghpMaxValue, G.GHP_UNIT AS ghpUnit, G.GHP_USAGE AS ghpUsage FROM GHP G LEFT JOIN WP_TYPE WP ON G.GHP_WP_TYPE = WP.WP_TYPE_NO LEFT JOIN WH_TYPE WH ON G.GHP_WH_TYPE = WH.WH_TYPE_NO
G.GHP_USAGE = 'Y'
AND G.GHP_CATEGORY = #{ghpCategorySearch}
AND ( UPPER(G.GHP_ID) LIKE UPPER('%' || #{searchKeyword} || '%') OR UPPER(G.GHP_NAME) LIKE UPPER('%' || #{searchKeyword} || '%') OR UPPER(G.GHP_STANDARD) LIKE UPPER('%' || #{searchKeyword} || '%') OR UPPER(WP.WP_TYPE_NAME) LIKE UPPER('%' || #{searchKeyword} || '%') )
ORDER BY G.GHP_ID DESC ) I ) where rn between #{page.startRow} and #{page.endRow}

mapper.update:
UPDATE GHP
SET GHP_USAGE = 'N'
WHERE GHP_ID = #{ghpId}
